def svg_icon(name, x, y, size=24, color="#F0EDF5", stroke=1.8, fill="none"):
    """Render um ícone Lucide como <g> pronto pra colar no SVG final.
    O ícone canônico é 24×24; aqui escalamos via transform."""
    if name not in LUCIDE:
        raise KeyError(f"icon '{name}' não está no LUCIDE dict")
    scale = size / 24.0
    inner = LUCIDE[name]
    return (
        f'<g transform="translate({x} {y}) scale({scale:.4f})" '
        f'fill="{fill}" stroke="{color}" stroke-width="{stroke}" '
        f'stroke-linecap="round" stroke-linejoin="round">{inner}</g>'
    )
